package com.example.cms.project;
import com.example.cms.common.response.ApiResponse;import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/project") public class ProjectManagementController{private final JdbcTemplate jdbc; public ProjectManagementController(JdbcTemplate jdbc){this.jdbc=jdbc;} private ApiResponse<List<Map<String,Object>>> list(String table){return ApiResponse.ok("목록",jdbc.queryForList("select * from "+table+" order by id"));} private ApiResponse<Map<String,Object>> create(String table,Map<String,Object> body){return ApiResponse.ok("저장",Map.of("table",table,"accepted",true,"input",body));} @GetMapping("/schedules") ApiResponse<List<Map<String,Object>>> schedules(){return list("project_schedules");} @PostMapping("/schedules") ApiResponse<Map<String,Object>> cs(@RequestBody Map<String,Object>b){return create("project_schedules",b);} @PatchMapping("/schedules/{id}") ApiResponse<Map<String,Object>> ps(@PathVariable Long id,@RequestBody Map<String,Object>b){return create("project_schedules",b);} @GetMapping("/requirements") ApiResponse<List<Map<String,Object>>> requirements(){return list("requirement_traces");} @PostMapping("/requirements") ApiResponse<Map<String,Object>> cr(@RequestBody Map<String,Object>b){return create("requirement_traces",b);} @PatchMapping("/requirements/{id}") ApiResponse<Map<String,Object>> pr(@PathVariable Long id,@RequestBody Map<String,Object>b){return create("requirement_traces",b);} @GetMapping("/members") ApiResponse<List<Map<String,Object>>> members(){return list("project_members");} @PostMapping("/members") ApiResponse<Map<String,Object>> cm(@RequestBody Map<String,Object>b){return create("project_members",b);} @PatchMapping("/members/{id}") ApiResponse<Map<String,Object>> pm(@PathVariable Long id,@RequestBody Map<String,Object>b){return create("project_members",b);} @GetMapping("/risk-issues") ApiResponse<List<Map<String,Object>>> risks(){return list("risk_issues");} @PostMapping("/risk-issues") ApiResponse<Map<String,Object>> ci(@RequestBody Map<String,Object>b){return create("risk_issues",b);} @PatchMapping("/risk-issues/{id}") ApiResponse<Map<String,Object>> pi(@PathVariable Long id,@RequestBody Map<String,Object>b){return create("risk_issues",b);} @GetMapping("/deliverables") ApiResponse<List<Map<String,Object>>> deliverables(){return list("deliverables");} @PostMapping("/deliverables") ApiResponse<Map<String,Object>> cd(@RequestBody Map<String,Object>b){return create("deliverables",b);} @PatchMapping("/deliverables/{id}") ApiResponse<Map<String,Object>> pd(@PathVariable Long id,@RequestBody Map<String,Object>b){return create("deliverables",b);} @GetMapping("/change-requests") ApiResponse<List<Map<String,Object>>> changes(){return list("change_requests");} @PostMapping("/change-requests") ApiResponse<Map<String,Object>> cc(@RequestBody Map<String,Object>b){return create("change_requests",b);} @PatchMapping("/change-requests/{id}") ApiResponse<Map<String,Object>> pc(@PathVariable Long id,@RequestBody Map<String,Object>b){return create("change_requests",b);} }
